def auto_resolv_deps(repo_path):
    import subprocess
    import os
    dep_file = os.path.join(repo_path, 'requirements.txt')
    if os.path.exists(dep_file):
        pip_args = ['-r', dep_file]
    else:
        # Handle other common manifests
        for ext in ['pyproject.toml', 'package.json', 'Cargo.toml', 'go.mod']:
            dep_file = os.path.join(repo_path, ext)
            if os.path.exists(dep_file):
                break
    subprocess.run(['pip', 'install'] + pip_args, cwd=repo_path, capture_output=True)
